// Parse account identification and store transcript for later use
const raw = $input.first().json.text;
const cleaned = raw.replace(/```json|```/g, '').trim();
const identity = JSON.parse(cleaned);

const company = identity.company_name || 'unknown';
const account_id = company
  .toLowerCase()
  .replace(/[^a-z0-9]/g, '_')
  .replace(/_+/g, '_')
  .replace(/^_|_$/g, '');

// Retrieve the original transcript text from Extract Text node
const transcript = $('Extract Text').first().json.data;

return [{ json: { account_id, company_name: company, transcript } }];

// Abort: no v1 found for this account
const account_id = $('Parse Account ID').first().json.account_id;
throw new Error(`No v1 account_memo.json found for account: ${account_id}. Run Pipeline A first.`);

// Combine v1 memo text with onboarding transcript for the LLM
const v1_memo_text = $input.first().json.data;
const { account_id, company_name, transcript } = $('Parse Account ID').first().json;

return [{ json: { v1_memo_text, transcript, account_id, company_name } }];

const raw = $input.first().json.text;
const cleaned = raw.replace(/```json|```/g, '').trim();
const result = JSON.parse(cleaned);

const { account_id, company_name } = $('Parse Account ID').first().json;
const v1_memo_text = $('Combine v1 + Transcript').first().json.v1_memo_text;
const v1_memo = JSON.parse(v1_memo_text);

// Build v2 memo
const v2_memo = result.updated_memo;
v2_memo.account_id = account_id;
v2_memo.version = 'v2';
v2_memo.created_at = new Date().toISOString();
v2_memo.based_on_v1 = v1_memo.created_at;

// Build changelog
const changelog = {
  account_id,
  from_version: 'v1',
  to_version: 'v2',
  generated_at: new Date().toISOString(),
  total_changes: (result.changes || []).length,
  total_conflicts: (result.conflicts || []).length,
  changes: result.changes || [],
  conflicts: result.conflicts || []
};

return [{
  json: {
    v2_memo,
    v2_memo_text: JSON.stringify(v2_memo, null, 2),
    changelog,
    changelog_text: JSON.stringify(changelog, null, 2),
    account_id,
    company_name
  }
}];

const raw = $input.first().json.text;
const cleaned = raw.replace(/```json|```/g, '').trim();
const agent_spec = JSON.parse(cleaned);

const account_id = $('Build v2 Memo + Changelog').first().json.account_id;

agent_spec.account_id = account_id;
agent_spec.version = 'v2';
agent_spec.generated_at = new Date().toISOString();

return [{ json: { agent_spec_text: JSON.stringify(agent_spec, null, 2), account_id } }];

const { account_id, company_name, changelog } = $('Build v2 Memo + Changelog').first().json;

const title = `Review v2 Agent: ${company_name || account_id}`;
const description = `v2 account_memo and agent_spec generated for ${company_name || account_id} from onboarding call. ${changelog.total_changes} change(s), ${changelog.total_conflicts} conflict(s). Review outputs before deploying to Retell.

Outputs:
- account_memo: /outputs/accounts/${account_id}/v2/account_memo.json
- agent_spec: /outputs/accounts/${account_id}/v2/agent_spec.json
- changelog: /outputs/accounts/${account_id}/v2/changelog.json`;

const task = {
  task_id: `${account_id}_v2_${Date.now()}`,
  title,
  account_id,
  version: 'v2',
  status: 'pending_review',
  created_at: new Date().toISOString(),
  description,
  outputs: {
    account_memo: `/outputs/accounts/${account_id}/v2/account_memo.json`,
    agent_spec: `/outputs/accounts/${account_id}/v2/agent_spec.json`,
    changelog: `/outputs/accounts/${account_id}/v2/changelog.json`
  }
};

return [{ json: { task_text: JSON.stringify(task, null, 2), asana_title: title, asana_description: description } }];
